codingChallenges.solution:
text = "Modern Age Coders"
vowels = 0
consonants = 0
for ch in text:
    if ch.lower() in "aeiou":
        vowels += 1
    elif ch.isalpha():
        consonants += 1
print("Vowels:", vowels)
print("Consonants:", consonants)

text = "madam"
if text == text[::-1]:
    print(f"{text} is a palindrome")
else:
    print(f"{text} is not a palindrome")

text = "banana"
counted = ""
for ch in text:
    if ch not in counted:
        print(f"{ch}: {text.count(ch)}")
        counted += ch

text = "programming"
result = ""
for ch in text:
    if ch not in result:
        result += ch
print(result)

text = "aaabbccddddee"
result = ""
i = 0
while i < len(text):
    count = 1
    while i + count < len(text) and text[i + count] == text[i]:
        count += 1
    if count > 1:
        result += text[i] + str(count)
    else:
        result += text[i]
    i += count
print(result)
